def فرز_فقاعي(قائمة):
    ن = len(قائمة)
    for i in range(ن):
        for j in range(0, ن-i-1):
            if قائمة[j] > قائمة[j+1]:
                قائمة[j], قائمة[j+1] = قائمة[j+1], قائمة[j]
